+fn expand_tabs_at_col0(s: &str, tab_size: usize) -> String {
+    if tab_size == 0 || !s.contains('\t') {
+        return s.to_string();
+    }
+    let mut out = String::with_capacity(s.len());
+    for ch in s.chars() {
+        if ch == '\t' {
+            out.push_str(&" ".repeat(tab_size));
+        } else {
+            out.push(ch);
+        }
+    }
+    out
+}
